import sys
it = iter(sys.stdin.read().split())
n = int(next(it))
def solve(n):
    def is_valid(board, row, col):
        for i in range(row):
            if board[i] == col or \
                    board[i] - i == col - row or \
                    board[i] + i == col + row:
                return False
        return True
    def place_queens(n, row, board):
        if row == n:
            result.append(board[:])
            return
        for col in range(n):
            if is_valid(board, row, col):
                board[row] = col
                place_queens(n, row + 1, board)
    result = []
    place_queens(n, 0, [-1]*n)
    return result
solutions = solve(n)
print(len(solutions))
for solution in solutions:
    for row in range(n):
        line = ['.' for _ in range(n)]
        line[solution[row]] = 'Q'
        print(' '.join(line))

