#include <bits/stdc++.h>
using namespace std;
void solve(int n, int row, int* board, vector<vector<int>>& result){
    if(row == n){
        result.push_back(vector<int>(board, board + n));
        return;
    }
    for(int col = 0; col < n; col++){
        bool valid = true;
        for(int i = 0; i < row; i++){
            if(board[i] == col ||
                    board[i] - i == col - row ||
                    board[i] + i == col + row){
                valid = false;
                break;
            }
        }
        if(valid){
            board[row] = col;
            solve(n, row + 1, board, result);
        }
    }
}
int main(){
    int n;
    cin >> n;
    vector<vector<int>> result;
    int* board = new int[n];
    solve(n, 0, board, result);
    cout << result.size() << endl;
    for(auto& solution : result){
        for(int row = 0; row < n; row++){
            for(int col = 0; col < n; col++){
                cout << (col == solution[row] ? 'Q' : '.') << ' ';
            }
            cout << endl;
        }
    }
    delete[] board;
    return 0;
}
